import json
from python.router import get_intent  # Assuming you have or will convert router.js to router.py

test_queries = [
    "list the venues",
    "show users",
    "get entries from artist",
    "list files in ./venues",
    "What is 5 + 5?",
    "Read sample.txt",
    "How are you today?",
    "Tell me a story about a dragon.",
    "calculate 10!",
    "list files in ./venues"
]

for q in test_queries:
    intent = get_intent(q)
    # the intent is assumed to return a dict/object with path, tool, and args
    path = intent.get("path") if intent else None
    tool = intent.get("tool") if intent else None
    args_str = json.dumps(intent.get("args", {})) if intent else "{}"
    
    print(f'Query: "{q}" -> Path: {path}, Tool: {tool}, Args: {args_str}')
